  describe('Prop Defaults', () => {
    it('should declare prop "value" with type "String"', () => {
      const prop = { name: 'value', type: 'String', defaultValue: "#000000" };
      expect(prop.name).toBe('value');
      expect(prop.type).toBeTruthy();
    });

    it('should default "value" to "#000000"', () => {
      expect("#000000").toBe("#000000");
    });

    it('should declare prop "format" with type "hex | rgb | hsl | oklch"', () => {
      const prop = { name: 'format', type: 'hex | rgb | hsl | oklch', defaultValue: "hex" };
      expect(prop.name).toBe('format');
      expect(prop.type).toBeTruthy();
    });

    it('should default "format" to "hex"', () => {
      expect("hex").toBe("hex");
    });

    it('should declare prop "swatches" with type "option list String"', () => {
      const prop = { name: 'swatches', type: 'option list String' };
      expect(prop.name).toBe('swatches');
      expect(prop.type).toBeTruthy();
    });

    it('should declare prop "disabled" with type "Bool"', () => {
      const prop = { name: 'disabled', type: 'Bool', defaultValue: "false" };
      expect(prop.name).toBe('disabled');
      expect(prop.type).toBeTruthy();
    });

    it('should default "disabled" to "false"', () => {
      expect("false").toBe("false");
    });

    it('should declare prop "name" with type "option String"', () => {
      const prop = { name: 'name', type: 'option String' };
      expect(prop.name).toBe('name');
      expect(prop.type).toBeTruthy();
    });

    it('should declare prop "alpha" with type "Bool"', () => {
      const prop = { name: 'alpha', type: 'Bool', defaultValue: "false" };
      expect(prop.name).toBe('alpha');
      expect(prop.type).toBeTruthy();
    });

    it('should default "alpha" to "false"', () => {
      expect("false").toBe("false");
    });

  });

  describe('Anatomy Parts', () => {
    it('should declare all anatomy parts', () => {
      const parts = ["root","trigger","swatch","positioner","content","area","areaThumb","channelSlider","channelSliderTrack","channelSliderThumb","input","swatchGroup","swatchTrigger","eyeDropperButton"];
      expect(parts.length).toBe(14);
      expect(parts).toContain('root');
      expect(parts).toContain('trigger');
      expect(parts).toContain('swatch');
      expect(parts).toContain('positioner');
      expect(parts).toContain('content');
      expect(parts).toContain('area');
      expect(parts).toContain('areaThumb');
      expect(parts).toContain('channelSlider');
      expect(parts).toContain('channelSliderTrack');
      expect(parts).toContain('channelSliderThumb');
      expect(parts).toContain('input');
      expect(parts).toContain('swatchGroup');
      expect(parts).toContain('swatchTrigger');
      expect(parts).toContain('eyeDropperButton');
    });

    it('should assign semantic roles to anatomy parts', () => {
      expect('container').toBeTruthy(); // root: container
      expect('action').toBeTruthy(); // trigger: action
      expect('container').toBeTruthy(); // swatch: container
      expect('container').toBeTruthy(); // positioner: container
      expect('container').toBeTruthy(); // content: container
      expect('container').toBeTruthy(); // area: container
      expect('action').toBeTruthy(); // areaThumb: action
      expect('action').toBeTruthy(); // channelSlider: action
      expect('container').toBeTruthy(); // channelSliderTrack: container
      expect('action').toBeTruthy(); // channelSliderThumb: action
      expect('action').toBeTruthy(); // input: action
      expect('container').toBeTruthy(); // swatchGroup: container
      expect('action').toBeTruthy(); // swatchTrigger: action
      expect('action').toBeTruthy(); // eyeDropperButton: action
    });

  });

